sys_script_include.script:
var CMDBCertificateService = Class.create();
CMDBCertificateService.prototype = {
    initialize: function() {
        this.logger = new Logger('CMDBCertificateService');
    },

    attachCertificateFile: function(gr, certDetails, updateAttachment) {
        if (certDetails.state !== Constants.CERTIFICATE.statuses.Issued) {
            return;
        }

        var attachment = new GlideSysAttachment();
        if (updateAttachment) {
            // delete previous attachment
            attachment.deleteAttachment(gr.certificate_file);
        }

        var fileName = 'certificate.cer';
        var contentType = 'text/plain';
        var content = certDetails.certificate;
        // create new attachment
        var attachmentSysId = attachment.write(gr, fileName, contentType, content);

        gr.certificate_file = attachmentSysId;
        gr.update();

        if (attachmentSysId) {
            this.logger.debug("'certificate_file' created: {0}, for 'cmdb_ci_certificate' record: {1}", attachmentSysId, gr.sys_id);
        } else {
            this.logger.error("Failed to create 'certificate_file' for 'cmdb_ci_certificate' record: {0}", gr.sys_id);
        }
    },

    // Function to save certificate
	// all fields that are marked as required should be provided to function call (otherwise saved data will be malformed)
    // type CertDetails = {
    //		certificate: string (required)
    //		cert_template: string
    //		thumb_print: string (required)
    //		key_size: string (required)
    //		signature_algorithm: string
    //		subject_country: string
    //		subject_distinguished_name: string
    //		subject_email: string
    //		subject_locality: string
    //		subject_organization: string
    //		subject_organizational_unit: string
    //		subject_state: string
    //		valid_from: Date (required)
    // 		valid_to: Date (required)
    //		issuer_common_name: string
    //		subject_common_name: string
    // 		serial_number: string
    // 		state: string (Issued | Installed | Revoked | Retired | Other) (required)
    // }
    saveCertificate: function(certDetails) {
        function setCertificateValues(gr, certDetails) {
			function parseKeySize(keySize) {
				var temp = keySize.split("_");
				var firstPart = temp[0];
				var secondPart = temp[1];

				return firstPart === "RSA" ? parseInt(secondPart) : undefined;
			}

            // Setting fields with the certificate details
            gr.cert_template = certDetails.cert_template;
            gr.thumb_print = certDetails.thumb_print;
            gr.key_size = parseKeySize(certDetails.key_size);
            gr.signature_algorithm = certDetails.signature_algorithm;
            gr.subject_country = certDetails.subject_country;
            gr.subject_distinguished_name = certDetails.subject_distinguished_name;
            gr.subject_email = certDetails.subject_email;
            gr.subject_locality = certDetails.subject_locality;
            gr.subject_organization = certDetails.subject_organization;
            gr.subject_organizational_unit = certDetails.subject_organizational_unit;
            gr.subject_state = certDetails.subject_state;

            gr.valid_from = certDetails.valid_from;
            gr.valid_to = certDetails.valid_to;
            gr.issuer_common_name = certDetails.issuer_common_name;
            gr.subject_common_name = certDetails.subject_common_name;
            gr.serial_number = certDetails.serial_number;
            gr.state = certDetails.state;

			gr.discovery_source = "Digicert ONE";
        }

        try {
            var gr = new GlideRecord('cmdb_ci_certificate');

            gr.addQuery('thumb_print', certDetails.thumb_print);
            gr.query();

            if (gr.next()) {
                setCertificateValues(gr, certDetails);
                gr.update();

                this.attachCertificateFile(gr, certDetails, true);
            } else {
                gr.initialize();
                setCertificateValues(gr, certDetails);
                gr.insert();

                this.attachCertificateFile(gr, certDetails, false);
            }
        } catch (error) {
            this.logger.error("Error saving certificate to CMDB: {0}, certDetails: {1}", error, JSON.stringify(certDetails, null, 2));
			throw error;
        }

        this.logger.debug("Certificate '{0}' saved to CMDB successfully", gr.sys_id);
        return gr.sys_id; // Return the sys_id of the newly created record
    },

    type: 'CMDBCertificateService'
};
